#[test]
fn complete_with_description() {
    let schema = json!({
        "username": string "用户名",
        "password": string "密码"
    });

    let completions = schema.complete(r#"{"#);
    for comp in completions {
        if comp.name == "username" {
            assert_eq!(comp.description, "用户名");
        } else if comp.name == "password" {
            assert_eq!(comp.description, "密码");
        }
    }
}

